/// <summary>
/// Extension class of <c>PurchPurchaseOrderDP</c> for text block management
/// </summary>
[ExtensionOf(classStr(PurchPurchaseOrderDP))]
final class FWFTextBlockPurchPurchaseOrderDP_Extension
{
}

Method.Source:
protected PurchPurchaseOrderHeader initializePurchaseOrderHeader(VendPurchOrderJour _vendPurchOrderJour)
{
    PurchPurchaseOrderHeader purchPurchaseOrderHeaderCreated = next initializePurchaseOrderHeader(_vendPurchOrderJour);

    FWFTextBlockReportTextInit::newParameters(purchPurchaseOrderHeaderCreated, _vendPurchOrderJour).addTexts();

    return purchPurchaseOrderHeaderCreated;
}

protected PurchPurchaseOrderTmp initializeOrderLine(PurchPurchaseOrderHeader _purchaseOrderHeader, boolean _highlightUpdated, PurchPurchaseOrderDPOrderLineQuerySelection _orderLineSelection)
{
    PurchPurchaseOrderTmp purchPurchaseOrderTmpCreated = next initializeOrderLine(_purchaseOrderHeader, _highlightUpdated, _orderLineSelection);

    if (purchPurchaseOrderTmpCreated.PurchOrderTransOrTaxTrans == NoYes::Yes)
    {
        FWFTextBlockReportTextInit::newParametersPoConform(purchPurchaseOrderTmpCreated, _orderLineSelection.parmPurchLineAllVersions(), this.isProformaPrint()).addTexts();
    }

    return purchPurchaseOrderTmpCreated;
}
